mapper.select:
SELECT a.attendance_id, a.attendance_date, a.check_in_time, a.attendance_status,
       IFNULL(l.lateness_reason, '없음') AS lateness_reason, l.approval_status
FROM attendance a
LEFT JOIN lateness l ON a.attendance_id = l.attendance_id
WHERE a.emp_id = #{empId}
  AND a.attendance_date BETWEEN #{startDate} AND #{endDate}

SELECT SUM(TIMESTAMPDIFF(HOUR, a.check_in_time, a.check_out_time)) AS total_work_hours,
       COUNT(*) AS total_work_days
FROM attendance a
WHERE a.emp_id = #{empId}
  AND a.attendance_date BETWEEN #{startDate} AND #{endDate}

SELECT a.attendance_id, a.attendance_date, a.attendance_status,
       IFNULL(l.lateness_reason, '없음') AS lateness_reason
FROM attendance a
LEFT JOIN lateness l ON a.attendance_id = l.attendance_id
WHERE a.emp_id = #{empId}
  AND a.attendance_date BETWEEN #{startDate} AND #{endDate}

SELECT lv.leave_id, lv.leave_start_date, lv.leave_end_date, lv.leave_type, lv.leave_status
FROM leave_history lv
WHERE lv.emp_id = #{empId}

SELECT a.attendance_id, a.emp_id, a.check_in_time, a.check_out_time, a.attendance_status,
       e.emp_name, d.dep_name
FROM attendance a
JOIN employees e ON a.emp_id = e.emp_id
JOIN department d ON e.dep_id = d.dep_id


        a.emp_id = #{empId}


        AND e.dep_id = #{departmentId}


        AND a.attendance_date BETWEEN #{startDate} AND #{endDate}

